CREATE TABLE name_words
(
    id         UUID PRIMARY KEY     DEFAULT gen_random_uuid(),
    word       TEXT        NOT NULL,
    kind       TEXT        NOT NULL CHECK (kind IN ('adjective', 'noun')),
    enabled    BOOLEAN     NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (word, kind)
);

-- Seeded with online-sourced and deduplicated English words.
-- Filtering applied: lowercase alphabetic tokens only, profanity list excluded.
-- Additional moderation removes sexual, hate, violence, abuse, and weapon terms.
